Thought: Now I will implement the main application logic in `index.js`. This will include the JWT secret configuration, the permission guard, the specific routes (auth, admin, user), and the error handling middleware to ensure resilience against unauthorized access and system breakdowns.
<code>
app_code = "const express = require('express');
const { expressjwt: jwt } = require('express-jwt');
const jwtPermissions = require('express-jwt-permissions');
const bodyParser = require('body-parser');

const app = express();

// Configuration
const jwtCheck = jwt({
  secret: 'your_secret_key',
  algorithms: ['HS256']
});

const guard = jwtPermissions({
  requestProperty: 'user',
  permissionsProperty: 'roles'
});

app.use(bodyParser.json());
app.use(jwtCheck);

// Routes
app.get('/auth', (req, res) => {
  res.status(200).send('Authenticated user area');
});

app.get('/admin', guard.check('admin'), (req, res) => {
  res.status(200).send('Admin area');
});

app.get('/user', guard.check('user'), (req, res) => {
  res.status(200).send('User area');
});

// Error handling for resilience
app.use(function(err, req, res, next) {
  if (err.name === 'UnauthorizedError') {
    res.status(401).send('Invalid or missing token');
  } else if (err.code === 'permission_denied') {
    res.status(403).send('Forbidden: Insufficient permissions');
  } else {
    res.status(500).send('Internal System Error');
  }
});

const PORT = 3000;
app.listen(PORT, () => {
  console.log(`PBAC Server running on port ${PORT}`);
});"

