Thought: Now I will create the API route handler that implements the S3 upload logic with UUID generation.
<code>
content = "import aws from "aws-sdk";
import { v4 as uuidv4 } from "uuid";

aws.config.update({
  region: "your-region", 
  accessKeyId: "your-access-key-id", 
  secretAccessKey: "your-secret-access-key"
});

const s3 = new aws.S3();

export default async (req, res) => {
  if (req.method === 'POST') {
    const file = req.files.file;
    const name = uuidv4();
    const params = {
      Bucket: "bucket-name",
      Key: `${name}.pdf`,
      Body: file.data,
      ACL: "public-read",
      ContentType: file.mimetype
    };

    try {
        const uploaded = await s3.upload(params).promise();
        console.log(`File uploaded successfully at ${uploaded.Location}`);
        res.json({ fileName: file.name, filePath: uploaded.Location });
    } catch (error) {
        console.error(error);
        res.status(500).json({ error: "Error uploading file" });
    }
  } else {
      res.status(500).json({ error: 'Wrong method' });
  }
};"
