Thought: Now I will implement the main server logic in server.js, including the login and /me endpoints.
<code>
content = "require('dotenv').config();
const express = require('express');
const jwt = require('jsonwebtoken');
const bcrypt = require('bcryptjs');
const app = express();
app.use(express.json());

// Simple users storage
var users = [
  {id:1, username:'user1', password:bcrypt.hashSync('password1', 8)},
  {id:2, username:'user2', password:bcrypt.hashSync('password2', 8)},
];

app.post('/login', (req, res) => {
    let user = users.find(user => user.username === req.body.username);
    if (!user) return res.status(400).send('Username not found.');

    var passwordIsValid = bcrypt.compareSync(req.body.password, user.password);
    if (!passwordIsValid) return res.status(401).send({ auth: false, token: null });

    var token = jwt.sign({ id: user.id }, process.env.SECRET, {
      expiresIn: 86400 // expires in 24 hours
    });

    res.status(200).send({ auth: true, token: token });
});

app.get('/me', (req, res) => {
    var token = req.headers['x-access-token'];
    if (!token) return res.status(401).send({ auth: false, message: 'No token provided.' });

    jwt.verify(token, process.env.SECRET, (err, decoded) => {
        if (err) return res.status(401).send({ auth: false, message: 'Unauthorized' });
        res.status(200).send({ auth: true, user: decoded });
    });
});

app.listen(3000, () => console.log('Server running on port 3000'));
"
