<code>
content = "const express = require('express');
const mongoose = require('mongoose');
const axios = require('axios');
const app = express();

app.use(express.json());

// Mongoose schema definition
const Book = mongoose.model('Book', new mongoose.Schema({
  title: String,
  description: String,
  year: Number,
  author: String
}));

// Connect to MongoDB
mongoose.connect('mongodb://localhost/bookcatalog', {useNewUrlParser: true, useUnifiedTopology: true});

// API endpoint
app.post('/addbook', async (req, res) => {
  try {
    const title = req.body.title;

    // External API call (using placeholder endpoint as requested)
    let response = await axios.get(`https://api.onlinelibrary.com/books?title=${encodeURIComponent(title)}`);
    let bookData = response.data;

    // Save the book data in the database
    let book = new Book({
      title: bookData.title,
      description: bookData.description,
      year: bookData.year,
      author: bookData.author
    });

    await book.save();
    res.status(200).send(book);
  } catch (err) {
    res.status(500).send("There was a problem adding book: " + err.message);
  }
});

// Start Server
app.listen(3000, () => {
  console.log("Server is running on port 3000");
});
"
