		fmt.Fprintf(os.Stderr, "Firestore To Cosmos: %v
", err)
		os.Exit(1)
	}
}

func firestore_to_cosmos() error {
	ctx := context.Background()

	// replace your Firestore project ID here
	firestoreClient, err := firestore.NewClient(ctx, "your-firestore-project-id")
	if err != nil {
		return err
	}
	defer firestoreClient.Close()

	cosmosClient := new(documentdb.DatabaseAccountsClient)

	iterator := firestoreClient.Collections(ctx)
	for {
		ref, err := iterator.Next()
		if err == iterator.Done {
			break
		}
		if err != nil {
			return err
		}

		iter := ref.Documents(ctx)
		for {
			docSnap, err := iter.Next()
			if err == iterator.Done {
				break
			}
			if err != nil {
				return err
			}

			data := schemaTransform(docSnap.Data())
			// replace by cosmos db url and key
			cosmosClient.CreateUpdateSQLContainer(ctx, "resourceGroupName", "accountName", "databaseName", "containerName", data)
		}
	}

	return nil
}

func schemaTransform(data map[string]interface{}) map[string]interface{} {
	// This function is responsible to transform schema of data,
	// the actual implementation depends on your specific needs
	return data
}
