Thought: Now I will write the `server.js` file. I'll implement the requested features: HTTPS server, token authentication, rate limiting, a system info endpoint, and logging.
<code>
content = "const fs = require('fs');
const express = require('express');
const https = require('https');
const rateLimit = require('express-rate-limit');
const os = require('os');

const PORT = process.env.PORT || 3000;
const app = express();

const VALID_TOKENS = new Set(['TOKEN1', 'TOKEN2', 'TOKEN3']);

const authenticate = (req, res, next) => {
  const token = req.header('Authorization');
  if (!VALID_TOKENS.has(token)) {
    console.log(`[${new Date().toISOString()}] Unauthorized access attempt with token: ${token}`);
    return res.status(401).json({ error: 'Invalid token' });
  }
  next();
};

const limiter = rateLimit({
  windowMs: 1 * 60 * 1000, 
  max: 10, 
  handler: (req, res) => {
    console.log(`[${new Date().toISOString()}] Rate limit exceeded for IP: ${req.ip}`);
    res.status(429).json({ error: 'Too many requests, please try again later.' });
  }
});

app.use(limiter);

app.use((req, res, next) => {
  console.log(`[${new Date().toISOString()}] ${req.method} ${req.url} from ${req.ip}`);
  next();
});

app.get('/', (req, res) => {
  res.send('Hello World!');
});

app.get('/status', authenticate, (req, res) => {
  res.json({
    uptime: process.uptime(),
    memoryUsage: process.memoryUsage(),
    cpuLoad: os.loadavg(),
    platform: os.platform(),
    arch: os.arch()
  });
});

app.use((err, req, res, next) => {
  console.error(`[${new Date().toISOString()}] Server Error: ${err.stack}`);
  res.status(500).json({ error: 'Internal Server Error' });
});

const options = {
  key: fs.readFileSync('/tmp/secure-api/ssl/key.pem'),
  cert: fs.readFileSync('/tmp/secure-api/ssl/cert.pem'),
};

https.createServer(options, app).listen(PORT, () => {
  console.log(`Secure server running on https://localhost:${PORT}`);
});
"
