public class AdvancedPeekingIterator {
    private int[] nums;
    private int current;

    public AdvancedPeekingIterator(int[] nums) {
        this.nums = nums;
        this.current = 0;
    }

    public int next() {
        return nums[current++];
    }

    public boolean hasNext() {
        return current < nums.length;
    }

    public int peek() {
        return nums[current];
    }

    public int previous() {
        return nums[--current];
    }

    public boolean hasPrevious() {
        return current > 0;
    }

    public static void main(String[] args) {
        int[] input = {1, 2, 3};
        AdvancedPeekingIterator it = new AdvancedPeekingIterator(input);
        System.out.println(it.next());       // 1
        System.out.println(it.peek());       // 2
        System.out.println(it.next());       // 2
        System.out.println(it.previous());   // 1
        System.out.println(it.hasPrevious()); // true
        System.out.println(it.next());       // 2
        System.out.println(it.hasNext());     // true
    }
}
