// Import necessary dependencies
use futures::stream::StreamExt;
use tiberius::{Config, Query, Client, AuthMethod};
use tokio::net::TcpStream;
use tokio_util::compat::TokioAsyncWriteCompatExt;

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Define the connection configuration
    let mut config = Config::new();
    config.host("{SERVER_NAME}");
    config.database("{DATABASE_NAME}");
    config.authentication(AuthMethod::sql_server("{USER_NAME}", "{PASSWORD}"));

    // Specify driver options
    config.options.use_gss_auth(true).use_mars(true);

    // Establish TCP connection
    let tcp = TcpStream::connect(config.get_addr()).await?;
    // Wrap the TCP stream for compatibility with tiberius
    let mut client = Client::connect(tcp.compat_write(), config).await?;

    // Define the SQL query to be used
    let query = "SELECT * FROM table_name";
    let mut stream = client.query(Query::simple(&query), &[]).await?;

    // Fetch all the rows asynchronously using a stream
    while let Some(row) = stream.next().await {
        let row = row?;

        // Print each row to the console
        println!("{:?}", row);
    }

    // Close the connection
    // Note: Explicit closing is not needed as Rust's RAII closes the connection
    // automatically when the 'client' variable goes out of scope.
    Ok(())
}
