const app = express();
const json2xml = require('json2xml');

app.use(express.json());

app.post('/json2xml', function(req, res) {
    try {  
        const json = req.body;
        if (!json || Object.keys(json).length === 0) {
            return res.status(400).send('Invalid or empty JSON provided');
