content = "import math

def is_prime(n):
    if n <= 1 or (n % 1 > 0):
        return False
    elif n <= 3:
        return True
    elif n % 2 == 0 or n % 3 == 0:
        return False
    i = 5
    while i * i <= n:
        if n % i == 0 or n % (i + 2) == 0:
            return False
        i += 6
    return True

def primes_from_list(l):
    if not isinstance(l, list):
        raise TypeError("Input should be a list")
    for i in l:
        if not isinstance(i, (int, float)):
            raise TypeError("List items should be numbers")
        if is_prime(i):
            yield i

if __name__ == '__main__':
    start_list = [-23, 45.56, 7, -18, 9, 11.5, 14, 39, -22, 29]
    for p in primes_from_list(start_list):
        print(p)
