public class RemoveElement {
    public static void main(String[] args) {
        // Step 2: Initialize the List
        List<String> myList = new ArrayList<String>();
        myList.add("Element1");
        myList.add("Element2");
        myList.add("Element2");
        myList.add("Element3");
