    <style>
        table { width: 100%; border-collapse: collapse; margin-bottom: 10px; }
        table, th, td { border: 1px solid black; padding: 10px; text-align: center; }
        th { cursor: pointer; position: relative; }
        .del-col { color: red; cursor: pointer; margin-left: 10px; font-weight: bold; }
        .del-row { color: red; cursor: pointer; font-weight: bold; }
        .editable { cursor: text; }
    </style>
</head>
<body>
    <div id="tableContainer"></div>
    <button id="prev">Prev</button>
    <button id="next">Next</button>

    <script>
        class DynamicTable {
            constructor(data, containerID) {
                this.data = data;
                this.container = document.getElementById(containerID);
                this.page = 0;
                this.pageSize = 3;
                this.sortCol = null;
                this.sortDirection = 1;
                this.render();
            }

            render() {
                this.container.innerHTML = '';
                const table = document.createElement('table');

                // Header Row
                const headerRow = document.createElement('tr');
                for (let j = 0; j < this.data[0].length; j++) {
                    const th = document.createElement('th');
                    th.innerText = `Col ${j + 1} `;
                    th.onclick = () => this.sort(j);

                    const delBtn = document.createElement('span');
                    delBtn.innerText = ' [X]';
                    delBtn.className = 'del-col';
                    delBtn.onclick = (e) => { e.stopPropagation(); this.deleteColumn(j); };

                    th.appendChild(delBtn);
                    headerRow.appendChild(th);
                }
                table.appendChild(headerRow);

                // Data Rows (with pagination)
                const startRow = this.page * this.pageSize;
                const endRow = Math.min(startRow + this.pageSize, this.data.length);

                for (let i = startRow; i < endRow; i++) {
                    const tr = document.createElement('tr');
                    for (let j = 0; j < this.data[i].length; j++) {
                        const td = document.createElement('td');
                        td.id = `cell-${i}-${j}`;
                        td.className = 'editable';
                        td.innerText = this.data[i][j];
                        td.contentEditable = true;
                        td.onblur = () => { this.data[i][j] = td.innerText; };
                        tr.appendChild(td);
                    }

                    const delRowBtn = document.createElement('td');
                    const btn = document.createElement('button');
                    btn.innerText = 'Delete Row';
                    btn.className = 'del-row';
                    btn.onclick = () => this.deleteRow(i);
                    delRowBtn.appendChild(btn);
                    tr.appendChild(delRowBtn);

                    table.appendChild(tr);
                }
                this.container.appendChild(table);
            }

            sort(colIndex) {
                if (this.sortCol === colIndex) {
                    this.sortDirection *= -1;
                } else {
                    this.sortCol = colIndex;
                    this.sortDirection = 1;
                }
                this.data.sort((a, b) => {
                    return a[colIndex].localeCompare(b[colIndex]) * this.sortDirection;
                });
                this.render();
            }

            deleteRow(rowIndex) {
                this.data.splice(rowIndex, 1);
                this.render();
            }

            deleteColumn(colIndex) {
                this.data.forEach(row => row.splice(colIndex, 1));
                this.render();
            }

            nextPage() {
                if ((this.page + 1) * this.pageSize < this.data.length) {
                    this.page++;
                    this.render();
                }
            }

            prevPage() {
                if (this.page > 0) {
                    this.page--;
                    this.render();
                }
            }
        }

        const initialData = [
            ['A1', 'B1', 'C1'],
            ['A2', 'B2', 'C2'],
            ['A3', 'B3', 'C3'],
            ['A4', 'B4', 'C4'],
            ['A5', 'B5', 'C5'],
            ['A6', 'B6', 'C6'],
            ['A7', 'B7', 'C7'],
            ['A8', 'B8', 'C8'],
            ['A9', 'B9', 'C9'],
            ['A10', 'B10', 'C10']
        ];

        const myTable = new DynamicTable(initialData, 'tableContainer');
        document.getElementById('prev').onclick = () => myTable.prevPage();
        document.getElementById('next').onclick = () => myTable.nextPage();
    </script>
</body>
</html>
"""
