  const app = express();
  const port = process.env.PORT || 3000;

  app.get('/', (req, res) => {
    res.send('Hello World! Scalable Node.js Server is running.');
  });

  app.listen(port, () => {
    console.log(`Worker ${process.pid} started listening on port ${port}`);
  });
}"
