calc_logic = """
export const calculateStats = (nums) => {
  if (!nums || nums.length === 0) return null;
  const sum = nums.reduce((a, b) => a + b, 0);
  const product = nums.reduce((a, b) => a * b, 1);
  return {
    sum,
    product,
    average: sum / nums.length,
    min: Math.min(...nums),
    max: Math.max(...nums),
  };
};

export const validateInput = (inputStr) => {
  const parts = inputStr.split(',').map(s => s.trim());
  const nums = [];
  for (let p of parts) {
    const n = parseInt(p, 10);
    if (isNaN(n) || n <= 0 || n.toString() !== p) {
      throw new Error('Please enter positive integers only');
    }
    nums.push(n);
  }
  return nums;
};
"""
