Thought: Now I'll implement the Redux-Saga to handle the side effects: validating the input and triggering the calculations.
<code>
saga_logic = """
import { call, put, takeEvery } from 'redux-saga/effects';
import { validateInput, calculateStats } from '../utils/calc';
import { setNumbers, setStats, setError, setSortedList } from './numbersSlice';

function* handleProcessNumbers(action) {
  try {
    const nums = yield call(validateInput, action.payload);
    yield put(setNumbers(nums));
    const stats = yield call(calculateStats, nums);
    yield put(setStats(stats));
  } catch (e) {
    yield put(setError(e.message));
  }
}

function* handleSort(action) {
  const { list, direction } = action.payload;
  const sorted = [...list].sort((a, b) => direction === 'asc' ? a - b : b - a);
  yield put(setSortedList(sorted));
}

export default function* rootSaga() {
  yield takeEvery('PROCESS_NUMBERS_REQUEST', handleProcessNumbers);
  yield takeEvery('SORT_NUMBERS_REQUEST', handleSort);
}
"""
write_file(path="/tmp/numbers-app/src/store/rootSaga.js", content=saga_logic)
