import com.google.common.cache.CacheBuilder;
import java.sql.*;

public class JDBCExample {
    static final String JDBC_DRIVER = "com.mysql.cj.jdbc.Driver";
    static final String DB_URL = "jdbc:mysql://localhost/GPT";
    static final String USER = "GPTuser";
    static final String PASS = "GPT123";

    private final Cache<String, PreparedStatement> cache;

    JDBCExample() {
        cache = CacheBuilder.newBuilder()
                .maximumSize(100)
                .build();
    }

    public void performCRUD() {
        Connection conn = null;
        try {
            Class.forName(JDBC_DRIVER);
            conn = DriverManager.getConnection(DB_URL, USER, PASS);
            conn.setAutoCommit(false);

            // Create Table
            try (Statement stmt = conn.createStatement()) {
                stmt.execute("CREATE TABLE IF NOT EXISTS PERSONS (id INTEGER NOT NULL, name VARCHAR(255), age INTEGER, PRIMARY KEY (id))");
            }

            // Create (Insert)
            String insertSql = "INSERT INTO PERSONS (id, name, age) VALUES (?, ?, ?)";
            try (PreparedStatement pstmt = conn.prepareStatement(insertSql)) {
                pstmt.setInt(1, 1);
                pstmt.setString(2, "John Doe");
                pstmt.setInt(3, 30);
                pstmt.executeUpdate();
            }

            // Read
            String selectSql = "SELECT * FROM PERSONS WHERE id = ?";
            try (PreparedStatement pstmt = conn.prepareStatement(selectSql)) {
                pstmt.setInt(1, 1);
                ResultSet rs = pstmt.executeQuery();
                while (rs.next()) {
                    System.out.println("Name: " + rs.getString("name"));
                }
            }

            // Update
            String updateSql = "UPDATE PERSONS SET name = ? WHERE id = ?";
            try (PreparedStatement pstmt = conn.prepareStatement(updateSql)) {
                pstmt.setString(1, "Jane Doe");
                pstmt.setInt(2, 1);
                pstmt.executeUpdate();
            }

            // Delete
            String deleteSql = "DELETE FROM PERSONS WHERE id = ?";
            try (PreparedStatement pstmt = conn.prepareStatement(deleteSql)) {
                pstmt.setInt(1, 1);
                pstmt.executeUpdate();
            }

            conn.commit();
        } catch (Exception e) {
            if (conn != null) try { conn.rollback(); } catch (SQLException ex) { ex.printStackTrace(); }
            e.printStackTrace();
        } finally {
            if (conn != null) try { conn.close(); } catch (SQLException e) { e.printStackTrace(); }
        }
    }

    public static void main(String[] args) {
        new JDBCExample().performCRUD();
    }
}"
