content = "const express = require('express');
const mongoose = require('mongoose');
const helmet = require('helmet');
const morgan = require('morgan');

const app = express();
app.use(helmet());
app.use(morgan('dev'));
app.use(express.json());

mongoose.connect('mongodb://localhost:27017/quotes_db')
  .then(() => console.log('Connected to MongoDB'))
  .catch(err => console.error('Could not connect to MongoDB', err));

const quoteSchema = new mongoose.Schema({
  quote: { type: String, required: true },
  author: { type: String, required: true },
  genre: { type: String, required: true },
  createdAt: { type: Date, default: Date.now }
});

const Quote = mongoose.model('Quote', quoteSchema);

// POST /quotes - Create a quote
app.post('/quotes', async (req, res) => {
  try {
    const { quote, author, genre } = req.body;
    const newQuote = new Quote({ quote, author, genre });
    await newQuote.save();
    res.status(201).send(newQuote);
  } catch (error) {
    res.status(400).send({ error: 'Invalid request data' });
  }
});

// GET /quotes - Retrieve quotes with filtering and sorting
app.get('/quotes', async (req, res) => {
  try {
    const { author, genre, sortBy, order } = req.query;
    let filter = {};
    if (author) filter.author = author;
    if (genre) filter.genre = genre;

    let sortOptions = {};
    if (sortBy === 'date') sortOptions.createdAt = order === 'desc' ? -1 : 1;
    else if (sortBy === 'author') sortOptions.author = order === 'desc' ? -1 : 1;

    const quotes = await Quote.find(filter).sort(sortOptions);
    res.send(quotes);
  } catch (error) {
    res.status(500).send({ error: 'Server error' });
  }
});

// GET /quotes/:id - Retrieve a specific quote
app.get('/quotes/:id', async (req, res) => {
  try {
    const quote = await Quote.findById(req.params.id);
    if (!quote) return res.status(404).send({ error: 'Quote not found' });
    res.send(quote);
  } catch (error) {
    res.status(400).send({ error: 'Invalid ID format' });
  }
});

// PUT /quotes/:id - Update a quote
app.put('/quotes/:id', async (req, res) => {
  try {
    const quote = await Quote.findByIdAndUpdate(req.params.id, req.body, { new: true });
    if (!quote) return res.status(404).send({ error: 'Quote not found' });
    res.send(quote);
  } catch (error) {
    res.status(400).send({ error: 'Update failed' });
  }
});

// DELETE /quotes/:id - Delete a quote
app.delete('/quotes/:id', async (req, res) => {
  try {
    const quote = await Quote.findByIdAndDelete(req.params.id);
    if (!quote) return res.status(404).send({ error: 'Quote not found' });
    res.send({ message: 'Quote deleted successfully' });
  } catch (error) {
    res.status(400).send({ error: 'Delete failed' });
  }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
