        Handle POST requests to create a new user.
        \"""
        try:
            # Support both form-data and JSON body
            if request.content_type == 'application/json':
                data = json.loads(request.body)
            else:
                data = request.POST

            username = data.get('username')
            password = data.get('password')
            email = data.get('email')
            interests = data.get('interests', [])

            if not all([username, password, email]):
                return JsonResponse({'error': 'Missing required information: username, password, and email are required.'}, status=400)

            # Ensure interests is a list
            if isinstance(interests, str):
                try:
                    interests = json.loads(interests)
                except json.JSONDecodeError:
                    return JsonResponse({'error': 'Interests must be a valid JSON list.'}, status=400)

            if not isinstance(interests, list):
                return JsonResponse({'error': 'Interests must be a list.'}, status=400)

            # Create user using create_user to handle password hashing
            user = User.objects.create_user(
                username=username,
                password=password,
                email=email,
                interests=interests
            )
