  try {
    // 1. Check Cache
    const cachedData = await client.get(cacheKey);
    if (cachedData) {
      return res.json(JSON.parse(cachedData));
    }

    // 2. Complex PostgreSQL Query
    // Using a parameterized query to prevent SQL injection for pagination
    const products = await db.query(
