Thought: I need to implement a BSTIterator that performs an in-order traversal. To achieve O(1) average time and O(h) space, I will use a stack to store the path to the current smallest element. I'll write the implementation to a file and then verify it with a test script.
<code>
content = "class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

class BSTIterator:
    def __init__(self, root: TreeNode):
        self.stack = []
        self._inorder_left(root)

    def _inorder_left(self, root):
        while root:
            self.stack.append(root)
            root = root.left

    def next(self) -> int:
        topmost_node = self.stack.pop()
        if topmost_node.right:
            self._inorder_left(topmost_node.right)
        return topmost_node.val

    def hasNext(self) -> bool:
        return len(self.stack) > 0
"
