<code>
content = "<?php
class MyIterator implements Iterator {
    private $data = [1, 2, 3];
    private $position = 0;

    public function current() { return $this->data[$this->position]; }
    public function key() { return $this->position; }
    public function next(): void {
        $this->position++;
        next($this->data);
