    designation: { type: String, required: true },
    age: { type: Number, min: 0, required: true },
    role: { type: String, required: true },
    pastJobs: { type: [JobSchema], default: [] },
    skills: { type: Map, of: Number },
    seekingJob: { type: Boolean, default: false },
    updatedAt: { type: Date, default: Date.now },
}, { timestamps: true });

// Efficient querying index
UserSchema.index({ designation: 1, age: 1, role: 1 });

// Custom validation for skill proficiency (0-10)
UserSchema.path('skills').validate((value) => {
    if (!value) return true;
    for (const [_, rating] of value.entries()) {
        if (rating < 0 || rating > 10) return false;
    }
    return true;
}, 'Invalid proficiency rating: must be between 0 and 10');

// Update timestamp on updateOne
UserSchema.pre('updateOne', function (next) {
    this.set({ updatedAt: new Date() });
    next();
});

// Logic: when a new job is added, set seekingJob to false
UserSchema.pre('save', function (next) {
    if (this.isModified('pastJobs')) {
        this.seekingJob = false;
    }
    this.updatedAt = new Date();
    next();
});

const User = mongoose.model('User', UserSchema);

