<code>
content = "package main

import (
	"database/sql"
	"fmt"
	"log"

	_ "github.com/lib/pq"
)

func executeQuery(db *sql.DB, query string) (results []map[string]interface{}, err error) {
	rows, err := db.Query(query)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	columns, err := rows.Columns()
	if err != nil {
		return nil, err
	}

	for rows.Next() {
		values := make([]interface{}, len(columns))
		pointers := make([]interface{}, len(values))
		for i := range values {
			pointers[i] = &values[i]
		}

		err := rows.Scan(pointers...)
		if err != nil {
			return nil, err
		}

		result := make(map[string]interface{})
		for i, colName := range columns {
			val := values[i]
			b, ok := val.([]byte)
			if ok {
				result[colName] = string(b)
			} else {
				result[colName] = val
			}
		}

		results = append(results, result)
	}

	if err := rows.Err(); err != nil {
		return nil, err
	}

	return results, nil
}

func main() {
	connStr := "user=postgres dbname=test sslmode=disable password=secret"
	db, err := sql.Open("postgres", connStr)
	if err != nil {
		log.Fatal(err)
		return
	}
	defer db.Close()

	query := "SELECT * FROM tablename"

	result, err := executeQuery(db, query)
	if err != nil {
		log.Fatal(err)
		return
	}

	fmt.Println(result)
}"
