final_answer("The error in the original code is that `res.send(result)` attempts to send a number directly. In Express, sending a number can be misinterpreted as an HTTP status code or fail because the HTTP protocol requires string/buffer bodies. 

Fix: Use `res.json()` instead of `res.send()`. This automatically converts the result to a JSON string and allows for a structured response (e.g., an object). 

Corrected Code:

```javascript
const express = require('express');
const app = express();

app.use(express.json());

app.post('/api/sum', (req, res) => {
  const { num1, num2 } = req.body;

  if (typeof num1 !== 'number' || typeof num2 !== 'number') {
    return res.status(400).json({ error: 'Inputs must be numbers' });
  }

  const result = num1 + num2;

  return res.json({ sum: result });
});

app.listen(3000, () => {
  console.log('Server listening on port 3000');
});
```")
