<code>
content = "const express = require('express');
const http = require('http');
const socketIO = require('socket.io');
const mongoose = require('mongoose');

const app = express();
const server = http.createServer(app);
const io = socketIO(server);

mongoose.connect('mongodb://localhost:27017/hangman', { useNewUrlParser: true, useUnifiedTopology: true });

const playerSchema = new mongoose.Schema({
  username: String,
  wins: { type: Number, default: 0 },
  losses: { type: Number, default: 0 },
  correctGuesses: { type: Number, default: 0 },
  incorrectGuesses: { type: Number, default: 0 },
});
const Player = mongoose.model('Player', playerSchema);

let gameState = { word: '', guessedLetters: [], players: {} };

io.on('connection', socket => {
  console.log('a user connected');

  socket.on('joinGame', async (username) => {
    socket.username = username;
    let player = await Player.findOne({ username });
    if (!player) player = await Player.create({ username });
    gameState.players[socket.id] = { username, stats: player };
    io.emit('updatePlayers', Object.values(gameState.players));
  });

  socket.on('guess', (letter) => {
    if (gameState.word.includes(letter)) {
      gameState.guessedLetters.push(letter);
      io.emit('gameUpdate', { state: 'correct', letters: gameState.guessedLetters });
    } else {
      io.emit('gameUpdate', { state: 'wrong', letters: gameState.guessedLetters });
    }
  });

  socket.on('chatMessage', (msg) => {
    io.emit('chatMessage', { user: socket.username, text: msg });
  });

  socket.on('disconnect', () => {
    delete gameState.players[socket.id];
    io.emit('updatePlayers', Object.values(gameState.players));
  });
});

server.listen(4001, () => console.log('Server listening on port 4001'));
"
