Thought: I need to implement an LRU cache in Java. The plan is to use a HashMap for O(1) lookups and a LinkedHashSet to maintain the order of usage. I'll start by writing the Java source code to a file.
<code>
content = "import java.util.HashMap;
import java.util.LinkedHashSet;

public class LRUCache {

    private final int capacity;
    private HashMap<Integer, Integer> cache;
    private LinkedHashSet<Integer> keys;

    public LRUCache(int capacity) {
        this.capacity = capacity;
        cache = new HashMap<>();
        keys = new LinkedHashSet<>();
    }

    public int get(int key) {
        if (!cache.containsKey(key))
            return -1;

        keys.remove(key);
        keys.add(key); // add key as the most recently used
        return cache.get(key);
    }

    public void put(int key, int value) {
        if (cache.containsKey(key)) {
            keys.remove(key);
        }
        else if (cache.size() >= capacity) {
            removeOldestEntry();
        }
        cache.put(key, value);
        keys.add(key);
    }

    private void removeOldestEntry() {
        int oldestKey = keys.iterator().next();
        keys.remove(oldestKey);
        cache.remove(oldestKey);
    }

    public static void main(String[] args) {
        LRUCache lru = new LRUCache(2);
        lru.put(1, 1);
        lru.put(2, 2);
        System.out.println("Get 1: " + lru.get(1)); // returns 1
        lru.put(3, 3); // evicts key 2
        System.out.println("Get 2: " + lru.get(2)); // returns -1
        lru.put(4, 4); // evicts key 1
        System.out.println("Get 1: " + lru.get(1)); // returns -1
        System.out.println("Get 3: " + lru.get(3)); // returns 3
        System.out.println("Get 4: " + lru.get(4)); // returns 4
    }
}"
