content = "def generate_prime_sequence(starting_number):
    # A function to check whether a number is prime or not
    def is_prime(num):
        if num < 2:
            return False
        for i in range(2, int(num**0.5)+1):
            if num % i == 0:
                return False
        return True

    # A generator yielding a sequence of prime numbers
    while True:
        if is_prime(starting_number):
            yield starting_number
        starting_number += 1

if __name__ == '__main__':
    # Test the function
    prime_generator = generate_prime_sequence(2)
    for _ in range(10):
