content = "const express = require('express');
const jwt = require('jsonwebtoken');
const app = express();
app.use(express.json());

let users = {}; 
const SECRET_KEY = 'secretKey';

app.post('/register', (req, res) => {
  let username = req.body.username;
  let password = req.body.password;
  if(users[username]) {
    return res.json({error: 'Username already exists'});
  }
  users[username] = password;
  res.json({success: 'User created'});
});

app.post('/login', (req, res) => {
  let username = req.body.username;
  let password = req.body.password;
  if(users[username] !== password) {
    return res.json({error: 'Invalid credentials'});
  }

  let token = jwt.sign({username: username}, SECRET_KEY);
  res.json({token: token});
});

function verifyToken(req, res, next) {
  let token = req.headers['authorization'];
  if(!token || !token.startsWith('Bearer ')) {
    return res.status(401).json({error: 'Missing or malformatted token'});
  }

  const jwtToken = token.split(' ')[1];
  try {
    const decoded = jwt.verify(jwtToken, SECRET_KEY);
    req.user = decoded;
    next();
  } catch (err) {
    return res.status(401).json({error: 'Invalid token'});
  }
}

app.get('/protected', verifyToken, (req, res) => {
  res.json({success: 'Access granted to protected API', user: req.user});
});

