const Sequelize = require('sequelize');

// Initialize sequelize
const sequelize = new Sequelize({
    dialect: 'sqlite',
    storage: './database.sqlite',
    logging: false
});

// Define 'User' model
const User = sequelize.define('User', {
    id: {
        type: Sequelize.INTEGER,
        primaryKey: true
    },
    lastLogin: Sequelize.DATE
});

// Initialize Express
const app = express();
app.use(express.json());

// Middleware to validate user id for routes that require it
const validateUser = async (req, res, next) => {
    const userId = req.params.userId;
    if (!userId) return next();

    try {
        const user = await User.findByPk(userId);
        if (!user) {
            return res.status(404).send('User not found');
        }
        req.user = user;
        next();
    } catch (err) {
        res.status(400).send('Invalid request');
    }
};

// 1. GET /datetime - current date and time in GMT
app.get('/datetime', (req, res) => {
    res.send(new Date().toGMTString());
});

// Apply validation middleware to the following routes
app.get('/:userId', validateUser, (req, res) => {
    // 2. GET /:userId - return last login time in GMT
    if (!req.user.lastLogin) {
        return res.send('User has never logged in');
    }
    res.send(req.user.lastLogin.toGMTString());
});

app.post('/:userId', validateUser, async (req, res) => {
