content = "function requirePermission(permission) {
  return function(req, res, next) {
    try {
      const { user } = req;

      if (!user) {
        return res.status(401).json({ error: 'Unauthorized: No user session found' });
      }

      if (user.permissions && Array.isArray(user.permissions) && user.permissions.includes(permission)) {
        return next();
      }

      return res.status(403).json({ error: 'Forbidden: Insufficient permissions' });
    } catch (error) {
      console.error('PBAC Middleware Error:', error);
      return res.status(500).json({ error: 'Internal Server Error occurred during authorization' });
    }
  }
}

