    this.start = start;
    this.end = end;
    this.arr = [];
    this.initialize = function(){
        for(let i=this.start; i<=this.end; i++){
            this.arr.push(i);
        }
        for(let i=this.arr.length -1; i > 0; i--){
            let j = Math.floor(Math.random() * (i+1));
            let temp = this.arr[i];
            this.arr[i] = this.arr[j];
            this.arr[j] = temp;
        }
    };
    this.next = function(){
        if(this.arr.length){
            return this.arr.pop();
        } else {
            return null;
        }
    }
};

let rngTicker = new RngTicker(20, 50);
rngTicker.initialize();

let results = [];
while(true) {
    let val = rngTicker.next();
    if (val === null) break;
    results.push(val);
}
